var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"탑 카운터?","JPN":"トップカウンター？","ENG":"Top Counter?","TWN":"TOP制裁者？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다네. 자네의 CRF 측정 등급은 관리국 설립 이래 최고 수준이지.","JPN":"ああ。\\n君のCRF測定ランクは管理局設立以来、最高レベルだ。","ENG":"Yes. Your CRF level is the highest we've seen, ever since the start of the Administration.","TWN":"沒錯，你的CRF測量等級，是管理局有史以來最高的。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"등록에 동의만 한다면 공식적인 경로를 통해 관리국 탑 카운터로 지정될 걸세.","JPN":"登録に同意すれば、公式的な手順で\\n管理局のトップカウンターとして指定されるだろう。","ENG":"If you agree, the Administration will officially designate you as Top Counter.","TWN":"只要你同意加入，就會透過正式的管道指定為最強制裁者！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"지난번에 찾아 온 행정관은 그런 말 안 하던데, 당신 누구야?","JPN":"この前来た行政官はそんなことを言ってなかったが、あんた何者だ？","ENG":"The officer I met last time didn’t mention that. Who are you?","TWN":"上次來找我的行政官沒提到這些，你是誰？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 행정관보다는 높은 직책에 있는 사람이지.","JPN":"その行政官よりは高い役職に就いている人間、と言っておこう。","ENG":"I’m someone who’s in a higher position than the officer you met before.","TWN":"當然是職位比那個行政官更高的人囉！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"탑 카운터로 지정되면 많은 혜택이 있어.","JPN":"トップカウンターに指定されると、その恩恵もたくさんある。","ENG":"Being Top Counter has a lot of benefits.","TWN":"成為最強制裁者有很多好處喔！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"명예나 금전적인 이야기는 차치하고서라도, 외부에 공개되지 않은 관리국의 최신 장비도 마음껏 사용할 수 있지.","JPN":"名誉や金銭的な話はもちろん、外部に公開されていない\\n管理局の最新装備も思う存分使える。","ENG":"Not to mention the money and honor that comes with it, but you can also use the most advanced tech the Administration has, more advanced than anything you could dream of.","TWN":"　"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"강해지고 싶지 않나? 지금보다 훨씬?","JPN":"強くなりたいだろ？　今よりもさらに。","ENG":"Don’t you want to be stronger? Far stronger than ever?","TWN":"你不想變得比現在更強嗎？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"미안하지만 사양하겠어.","JPN":"悪いが遠慮しとくよ。","ENG":"Sorry, but my answer is no.","TWN":"謝謝你的好意，我拒絕。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"좋아. 그럼 여기 사인을…… 음?","JPN":"よし。じゃあ、ここにサインを……うん？","ENG":"Okay, then sign here... huh?","TWN":"很好，那請你在這裡簽……什麼？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"사양한다고 했어.","JPN":"遠慮するって言ってんだ。","ENG":"I said no.","TWN":"我說我拒絕。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"관리국 소속이면 결국 용병이나 다름없잖아. 돈을 받고 일을 하는.","JPN":"管理局所属ってことは、つまり傭兵と変わらないだろ。\\n金をもらって仕事をする……","ENG":"Being in the Administration is not very different from being a mercenary, is it? You work and get paid.","TWN":"隸屬於管理局的意思不就跟傭兵一樣，就是拿錢辦事。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇긴 하지. 세계를 구하는 일에는 예산이 아주 많이 필요하니까.","JPN":"そうだな。世界を救うためには多額の予算が必要だ。","ENG":"You could say that. Saving the world costs a lot of money, you know.","TWN":"話是沒錯，但拯救世界需要很多預算吧？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네는 돈이 싫은가?","JPN":"君はお金が嫌いなのか？","ENG":"You don’t like money?","TWN":"你不喜歡錢嗎？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"돈이 필요 없다는 건 아니야. 무서워서 그렇지.","JPN":"お金が要らないわけじゃない。ただ、怖いだけだ。","ENG":"It’s not that. But I’m scared.","TWN":"不是我不需要錢，而是我怕！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그런 식으로 타협하기 시작하면, 언젠가 진짜 용병이 되어 버릴 것 같아서.","JPN":"そんな風に妥協し始めると、\\nいつか本当の傭兵になっちまいそうでな。","ENG":"I’m scared that I might actually become a mercenary someday, if I start to compromise like this.","TWN":"如果我這次選擇妥協，我怕我總有一天會真的變成傭兵！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이러니저러니 해도 내겐 용병이었던 아버지의 피가 흐르고 있으니까.","JPN":"なんだかんだ俺には傭兵だった父親の血が流れているから。","ENG":"I’m a mercenary’s son, after all.","TWN":"畢竟再怎麼說，我身上流的是傭兵父親的血。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"어리광일지도 모르지만…… 난 의뢰비가 아니라 의무를 통해 사람들을 구하고 싶어.","JPN":"勝手な話かもしれないが……\\n俺は報酬のためではなく、義務として人々を救いたい。","ENG":"You might think I’m being idealistic... but I want to save people as my duty, not for a profit.","TWN":"這麼說好像有點驕傲……但我想要的不是委託費，而是在透過義務救人。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};